queries.sparql:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
SELECT ?val WHERE {
  { SELECT ?rt (COUNT(DISTINCT ?r) AS ?nf) WHERE { ?l p:hasRoutes ?r ; p:restrictionsType ?rt . } GROUP BY ?rt }
  ?res p:type ?rt ; p:value ?val .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Routes } }
  FILTER(?nf = ?total)
}

